import{_ as n,o as i,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const a="/images/uebung044.jpg",m=JSON.parse('{"title":"Übung Lektion 27","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung27.md","filePath":"lektionen/uebung27.md"}'),s={name:"lektionen/uebung27.md"};function d(p,e,o,h,l,u){return i(),t("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-27" tabindex="-1">Übung Lektion 27 <a class="header-anchor" href="#ubung-lektion-27" aria-label="Permalink to &quot;Übung Lektion 27&quot;">​</a></h1><p>A) Setzen Sie im folgenden Satz die Ausdrücke in der Klammer im Lokativ (सप्तमी) Singular und - wo es sinnvoll ist - Plural ein. Beachten Sie den verschiedenen Sandhi, d.h. schreiben Sie jedsesmal den vollen Satz aus!</p><p>रामस् ... वसति । (ग्राम । गुरु । सत्यवान्कविः । पुत्रं लब्धुकामा ब्राह्मणी । गृह । तन्नगरम् । मुह्यञ्छत्रुः)</p><p>रामो ग्रामे वसति ।</p><p>रामो गुरौ वसत् । रामो गुरुषु वसति ।</p><p>रामः सत्यवति कवौ वसति । रामः सत्यत्सु कविषु वसति ।</p><p>रामः पुत्रं लब्धुकामायां  ब्राह्मअण्यां वसति । रामः पुत्रं लब्धुकामासु ब्राह्मणीषु वसति ।</p><p>रामो गृहे वसति । रामो गृहेषु वसति ।</p><p>रामस्तस्मिन्नगरे वसति ।</p><p>रामो मुह्यति शत्रौ वसति । रामो मुह्यत्सु शत्रुषु वसति ॥</p><p>B) Übersetzen Sie und lösen Sie die Komposita auf:</p><p>धर्मं वदति गुरौ दुर्जना न शृण्वन्ति ॥१॥ Böse Leute hören nicht zu, wenn der Lehrer spricht.</p><p>बुद्धकाले नरैरार्यसत्यानि श्रोतुं शक्यन्ते ॥२॥ बुद्धस्य काले । Zur Zeit eines Buddha können die Menschen die edlen Wahrheiten hören.</p><p>वसितसुवस्त्रां नरा लुभ्यन्ति । एवं सति सत्यो नरेभ्यः सुवस्त्राणीच्छन्ति ॥३॥ वसितानि शोभनानि वस्त्राणि यया ताम् । शोभनानि वस्त्राणि । Männer lieben eine Frau, die sich schön gekleidet hat. Deswegen wünschen sich gute Frauen von den Männern schöne Kleider.</p><p>पुत्रे मृते ऽपुत्रा ब्राह्मणी पुत्रं लब्धुं व्रतं करोति ॥४॥ पुत्रो नास्ति यास्याः सा । Nachdem ihr Sohn gestorben ist macht die sohnlose Brahmanin ein Gelübde, um einen Sohn zu bekommen.</p><p>उपनीतबालैर्गुरुकुल उष्यते ॥५॥ उपनीतैर्बालैः । गुरोः कुले । Nach der Initiation wohnen die Knaben in der Familie des Meisters.</p><p>यज्ञकाले विगते ऽनिष्टदेवा विस्मृतयज्ञब्राह्मणेभ्यः क्रुध्यन्ति ॥६॥ यज्ञस्य काले । नेष्टा देवाः । विस्मृतो यज्ञो यैस्तेभ्यो ब्राह्मएभ्यः । Da der Zeitpunkt für das Opfer verstrichen ist, sind die Götter, denen nicht geopfert wurde, auf die Brahmanen zornig, die das Opfer vergessen hatten.</p><p>गुरौ तिष्ठति बाल आसितुं नार्हति ॥७॥ Während der Meister steht darf ein Knabe nicht sitzen.</p><p>एवं काले गच्छति स्वाचारक्षत्रिय इष्टं धनं न लभते ॥८॥ साधुराचारो यस्य स क्षत्रियः । Während die Zeit so vergeht, erhält der Kṣatriya mit guter Lebensart nicht den gewünschten Wohlstand.</p><p>ब्राह्मण्यां महाकवावागच्छन्त्यां ब्राह्मणीपुत्रो ऽप्यागच्छति ॥९॥ महति कवौ । ब्राह्मण्याः पुत्रः । Währen die Brahmanin beim großen Dichter ankommt, kommt auch ihr Sohn.</p><p>गुरुषूपदिशत्सु सुनीतबाला वक्तुं नार्हन्ति ॥१०॥ सुष्ठु नीता बालाः । Wenn die Lehrer sprechen, dürfen wohlerzogene Kinder nicht schwätzen.</p><p><img src="'+a+'" alt=""><br> Abb.: गुरुषूपदिशत्सु सुनीतबाला वक्तुं नार्हन्ति<br> Uttarakhand = उत्तराखण्ड<br> [Bildquelle: Peter Davis. -- <a href="http://www.flickr.com/photos/pediddle/327799554/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/pediddle/327799554/</a>. -- Zugriff am 2008-12-29. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',23)])])}const g=n(s,[["render",d]]);export{m as __pageData,g as default};
